mapper.update:
UPDATE session_route
SET tool_session_id = #{toolSessionId}, updated_at = NOW()
WHERE welink_session_id = #{welinkSessionId}
  AND source_type = #{sourceType}

UPDATE session_route
SET status = #{status}, updated_at = NOW()
WHERE welink_session_id = #{welinkSessionId}
  AND source_type = #{sourceType}

UPDATE session_route
SET source_instance = #{newInstanceId}, updated_at = NOW()
WHERE welink_session_id = #{welinkSessionId}
  AND source_instance = #{deadInstanceId}
  AND status = 'ACTIVE'

mapper.delete:
DELETE FROM session_route
WHERE status = 'CLOSED'
  AND updated_at < #{cutoffTime}
